// Article data loaded from articles.json (generated by prebuild from Feishu)
import articlesData from './articles.json';

export interface Article {
  slug: string;
  title: string;
  title_localized?: Record<string, string>;
  category: 'tech' | 'industry' | 'company';
  date: string;
  author: string;
  excerpt: string;
  excerpt_localized?: Record<string, string>;
  content: string;
  content_localized?: Record<string, string>;
  image?: string;
  url?: string;  // Feishu document URL
}

// Supported locales
export const SUPPORTED_LOCALES = ['en', 'zh', 'ja', 'ko', 'de'] as const;
export type Locale = typeof SUPPORTED_LOCALES[number];

// Get localized content based on locale
export function getLocalizedContent(article: Article, locale: string): {
  title: string;
  content: string;
  excerpt: string;
} {
  // Chinese (zh) uses original content
  if (locale === 'zh') {
    return {
      title: article.title,
      content: article.content,
      excerpt: article.excerpt
    };
  }
  // For other locales (en, ja, ko, de), use translated content if available
  return {
    title: article.title_localized?.[locale] || article.title,
    content: article.content_localized?.[locale] || article.content,
    excerpt: article.excerpt_localized?.[locale] || article.excerpt
  };
}

// Transform raw article data to Article interface
function transformArticle(raw: any): Article {
  // Generate slug from id or title
  const slug = raw.slug || raw.id || raw.title?.toLowerCase().replace(/\s+/g, '-').replace(/[^a-z0-9-]/g, '') || 'article';

  // Determine category from title or default to tech
  let category: Article['category'] = 'tech';
  const titleLower = (raw.title || '').toLowerCase();
  if (titleLower.includes('industry') || titleLower.includes('趋势') || titleLower.includes('市场')) {
    category = 'industry';
  } else if (titleLower.includes('company') || titleLower.includes('公司') || titleLower.includes('认证') || titleLower.includes('achievement')) {
    category = 'company';
  }

  return {
    slug,
    title: raw.title || 'Untitled',
    title_localized: raw.title_localized || {},
    category,
    date: raw.lastSync ? new Date(raw.lastSync).toISOString().split('T')[0] : new Date().toISOString().split('T')[0],
    author: raw.author || 'China NewChip',
    excerpt: raw.excerpt || raw.title || '',
    excerpt_localized: raw.excerpt_localized || {},
    content: raw.content || `## ${raw.title || 'Article Content'}\n\nThis article is synced from Feishu.`,
    content_localized: raw.content_localized || {},
    image: raw.image || undefined,
    url: raw.url || raw.docUrl || undefined,
  };
}

// Load articles from JSON
const rawArticles: any[] = Array.isArray(articlesData) ? articlesData : [];
export const articles: Article[] = rawArticles.map(transformArticle);

export function getArticleBySlug(slug: string): Article | undefined {
  return articles.find((a) => a.slug === slug);
}

export function getAllArticles(): Article[] {
  return articles;
}

export function getArticlesByCategory(category: Article['category']): Article[] {
  return articles.filter((a) => a.category === category);
}
